INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (1746, 'دەمێ ل هەوه دبته شەڤ..', 'عن جَابِرِ بْنِ عَبْدِ الله رضي الله عنه يَقُولُ: قَالَ رَسُولُ اللهﷺ : «إِذَا كَانَ جُنْحُ اللَّيْلِ -أَوْ أَمْسَيْتُمْ- فَكُفُّوا صِبْيَانَكُمْ، فَإِنَّ الشَّيْطَانَ يَنْتَشِرُ حِينَئِذٍ، فَإِذَا ذَهَبَ سَاعَةٌ مِنَ اللَّيْلِ فَخَلُّوهُمْ، وَأَغْلِقُوا الْأَبْوَابَ، وَاذْكُرُوا اسْمَ الله، فَإِنَّ الشَّيْطَانَ لَا يَفْتَحُ بَابًا مُغْلَقًا، وَأَوْكُوا قِرَبَكُمْ، وَاذْكُرُوا اسْمَ الله، وَخَمِّرُوا آنِيَتَكُمْ وَاذْكُرُوا اسْمَ الله، وَلَوْ أَنْ تَعْرُضُوا عَلَيْهَا شَيْئًا، وَأَطْفِئُوا مَصَابِيحَكُمْ».', 'جابرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ل هه‌وه‌ بوو شه‌ڤ یان ئێڤار، زارۆكێن خۆ بگرن، چونكى شه‌یطان ل وى ده‌مى به‌لاڤ دبن، و گاڤا ده‌مه‌ك ژ شه‌ڤێ چوو ژ نوى وان به‌رده‌ن، و ده‌رگه‌هێن خۆ بگرن، و ناڤێ خودێ بینن، چونكى شه‌یطان وى ده‌رگه‌هى ڤه‌ناكه‌ت یێ هاتبته‌ گرتن، و كونێن ئاڤێ بنخێڤن، و ناڤێ خودێ ل سه‌ر بینن، و ئامانێن خۆ بپه‌چنن، و ناڤێ خودێ ل سه‌ر بینن، ئه‌گه‌ر خۆ هوین تشته‌كى بداننه‌ سه‌ر، و چرایێن خۆ بڤه‌مرینن.', NULL, true),
  (1756, 'قەنجییا د گەل عەبدان', 'عَنْ المَعْرُورِ بن سوید قَالَ: لَقِيتُ أَبَا ذَرٍّ رضي الله عنه بِالرَّبَذَةِ وَعَلَيْهِ حُلَّةٌ، وَعَلَى غُلَامِهِ حُلَّةٌ، فَسَأَلْتُهُ عَنْ ذَلِكَ، فَقَالَ: إِنِّي سَابَبْتُ رَجُلًا فَعَيَّرْتُهُ بِأُمِّهِ فَقَالَ لِي النَّبِيُّﷺ : «يَا أَبَا ذَرٍّ أَعَيَّرْتَهُ بِأُمِّهِ؟ إِنَّكَ امْرُؤٌ فِيكَ جَاهِلِيَّةٌ، إِخْوَانُكُمْ خَوَلُكُمْ، جَعَلَهُمْ الله تَحْتَ أَيْدِيكُمْ، فَمَنْ كَانَ أَخُوهُ تَحْتَ يَدِهِ فَلْيُطْعِمْهُ مِمَّا يَأْكُلُ، وَلْيُلْبِسْهُ مِمَّا يَلْبَسُ، وَلَا تُكَلِّفُوهُمْ مَـا يَـغْـلِـبُـهُـمْ، فَـإِنْ كَلَّفْتُمُوهُمْ فَأَعِينُوهُمْ».', 'مـه‌عــروورێ كـــوڕێ سـوه‌یدى دبێژت: من ئه‌بوو ذه‌ر -خودێ ژێ رازى بت- ل ره‌به‌ذه‌یێ دیت، كراسه‌ك د به‌ر بوو، و ئێكێ وه‌كى وى د به‌ر عه‌بدێ وى ژى بوو، من پسیارا ڤێ چه‌ندێ ژێ كر، وى گۆت: شه‌ڕه‌ده‌ڤه‌ك د ناڤبه‌را من و زه‌لامه‌كى دا چێبوو، من تان ب ده‌یكا وى دانایێ (ده‌یكا وى جاریه‌ بوو) ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- گۆته‌ من: ئه‌بوو ذه‌ر، تو وى ب ده‌یكا وى كێم دكه‌ى؟ تــو مــرۆڤـه‌كى جاهلییه‌ت ل نك ته‌ هه‌یه‌! ئه‌و برایێن هه‌وه‌نه‌ خودێ كرینه‌ د بن ده‌ستێ هه‌وه‌ڤه‌، ڤێجا هه‌چییێ برایێ وى د بن ده‌ستێ وى ڤه‌ بت بلا خوارنێ ژ وێ بده‌تێ یا ئه‌و دخۆت، و جلكى ژ وێ بكه‌ته‌ به‌ر یا ئه‌و دكه‌ته‌ به‌ر خۆ، و زێده‌تر ژ شیانا وان بارى لێ نه‌كه‌ن، و ئه‌گه‌ر هه‌وه‌ ئه‌و بار لێ كر هوین هارى وان بكه‌ن.', NULL, true),
  (1766, 'ئەوێن خێرا وان دوقات', 'عَنْ أَبِي مُوسَى رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «ثَلَاثَةٌ لَهُمْ أَجْرَانِ: رَجُلٌ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ وَآمَنَ بِمُحَمَّدٍﷺ، وَالْعَبْدُ المَمْلُوكُ إِذَا أَدَّى حَقَّ الله وَحَقَّ مَوَالِيهِ، وَرَجُلٌ كَانَتْ عِنْدَهُ أَمَةٌ فَأَدَّبَهَا فَأَحْسَنَ تَأْدِيبَهَا، وَعَلَّمَهَا فَأَحْسَنَ تَعْلِيمَهَا، ثُمَّ أَعْتَقَهَا فَتَزَوَّجَهَا، فَلَهُ أَجْرَانِ».', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: سێ كه‌س هه‌نه‌ خێرا وان دوقاته‌: زه‌لامه‌كێ كیتابى باوه‌رى ب پێغه‌مبه‌رێ خۆ و ب موحه‌ممه‌دى ژى -سلاڤ لێ بن- ئینابت، و ئه‌و كۆله‌یێ حه‌قێ خودێ و حه‌قێ سه‌ییدێ خۆ ژى ژ سه‌ر خۆ ڕاكه‌ت، و زه‌لامه‌كێ جاریه‌ك هه‌بت ڤێجا ئه‌و وێ تازه‌ تۆره‌ بده‌ت، و باش فێر بكه‌ت، پاشى وێ ئازا كه‌ت و ل خۆ ماره‌ بكه‌ت، ئه‌وى دو خێر بۆ هه‌نه‌.', NULL, true),
  (1776, 'كەسێ ژ جهێ وى ڕانەكه', 'عَنِ ابْنِ عُمَرَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «لَا يُقِيمُ الرَّجُلُ الرَّجُلَ مِنْ مَقْعَدِهِ، ثُمَّ يَجْلِسُ فِيهِ، وَلَكِنْ تَفَسَّحُوا وَتَوَسَّعُوا».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: بلا چو زه‌لام چو زه‌لامێن دى ژ جهێ وى ڕانه‌كه‌ت پاشى ل جهێ وى بڕوینت، به‌لێ جهێ ئێك و دو بكه‌ن.', NULL, true),
  (1786, 'مەتەلا هەڤالێ باش و یێ خراب', 'عَنْ أَبِي مُوسَى رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «إِنَّمَا مَثَلُ الجَلِيسِ الصَّالِحِ، وَالجَلِيسِ السَّوْءِ، كَحَامِلِ الْمِسْكِ، وَنَافِخِ الْكِيرِ، فَحَامِلُ الْمِسْكِ: إِمَّا أَنْ يُحْذِيَكَ، وَإِمَّا أَنْ تَبْتَاعَ مِنْهُ، وَإِمَّا أَنْ تَجِدَ مِنْهُ رِيحًا طَيِّبَةً، وَنَافِخُ الْكِيرِ: إِمَّا أَنْ يُحْرِقَ ثِيَابَكَ، وَإِمَّا أَنْ تَجِدَ رِيحًا خَبِيثَةً».', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: مه‌ته‌لا هه‌ڤالێ باش و هه‌ڤالێ خراب (یێ تو ل نك دڕوینى) وه‌كى مه‌ته‌لا هلگرێ مسكێ و خودانێ كویرهێیه‌، هلگرێ مسكێ یان دێ هنده‌كێ ده‌ته‌ ته‌، یان تو دێ ژێ كڕى، یان دێ بێنه‌كا خۆش ژێ سه‌ح كه‌ى، و ئه‌وێ پف دكه‌ته‌ كویرهێ یان دێ كراسێ ته‌ سوژت، یان تو دێ بێنه‌كا نه‌خۆش ژێ سه‌ح كه‌ى.', NULL, true),
  (1796, 'ئەو گونەهكارێن نەئێنه عەفیكرن', 'عن أَبَي هُرَيْرَةَ رضي الله عنه يَقُولُ: سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «كُلُّ أُمَّتِي مُعَافًى إِلَّا المُجَاهِرِينَ، وَإِنَّ مِنْ المُجَاهَرَةِ أَنْ يَعْمَلَ الرَّجُلُ بِاللَّيْلِ عَمَلًا ثُمَّ يُصْبِحَ وَقَدْ سَتَرَهُ الله عَلَيْهِ فَيَقُولَ: يَا فُلَانُ، عَمِلْتُ الْبَارِحَةَ كَذَا وَكَذَا، وَقَدْ بَاتَ يَسْتُرُهُ رَبُّهُ، وَيُصْبِحُ يَكْشِفُ سِتْرَ الله عَنْهُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: من گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: ل ئوممه‌تا من هه‌مییێ دئێته‌ بۆرین ئه‌و تێ نه‌بن یێن خۆ ئاشكه‌را دكه‌ن، و ژ خۆئاشكه‌راكرنێیه‌ كو زه‌لام ب شه‌ڤ كاره‌كى بكه‌ت و لێ ببته‌ سپێده‌ و خودێ ئه‌و ستاره‌ كربت، ڤێجا بێژت: ئه‌ى فلان، دوهى من هۆ كر و هۆ كر، و ل وى بووبوو شه‌ڤ خودێ ئه‌و ستاره‌ كربوو، سپێدێ ئه‌و ڕادبت ستاره‌یێ خودێ ژ سه‌ر خۆ ڕادكه‌ت.', NULL, true),
  (1806, 'بناخەیێن موبایەعەیا صەحابییەكى', 'عَنْ جَرِيرِ بنِ عبدِ الله رضي الله عنه قَالَ: بَايَعْتُ رَسُولَ اللهﷺ عَلَى إِقَامِ الصَّلَاةِ، وَإِيتَاءِ الزَّكَاةِ، وَالنُّصْحِ لِكُلِّ مُسْلِمٍ.', 'جه‌ریرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: من به‌یعه‌ دا پێغه‌مبه‌رێ خودێ -سلاڤ لێ بن- ل سه‌ر كرنا نڤێژێ، و دانا زه‌كاتێ، و شیره‌تێ بۆ هه‌مى موسلمانان.', NULL, true),
  (1816, 'دلۆڤانییا پێغەمبەرى د گەل زارۆكان', 'عن أَنَسِ بْنِ مَالِكٍ رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «إِنِّي لَأَدْخُلُ فِي الصَّلَاةِ وَأَنَا أُرِيدُ إِطَالَتَهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ فِي صَلَاتِي مِمَّا أَعْلَمُ مِنْ شِدَّةِ وَجْدِ أُمِّهِ مِنْ بُكَائِهِ».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌ز دچمه‌ د نڤێژێ دا و من دڤێت ئه‌ز وێ درێژ بكه‌م، به‌لێ من گوهـ ل گرییا زارۆكى دبت ڤێجا ئه‌ز له‌زێ ل نڤێژا خۆ دكه‌م ژ به‌ر كو ئه‌ز دزانم چه‌ند دلێ ده‌یكا وى یێ ب دویڤ وى ڕا ژ به‌ر گرییا وى.', NULL, true),
  (1826, 'دڤێت ئیمام نڤێژێ زێده درێژ نەكەت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «إِذَا أَمَّ أَحَدُكُمُ النَّاسَ، فَلْيُخَفِّفْ، فَإِنَّ فِيهِمُ الصَّغِيرَ، وَالْكَبِيرَ، وَالضَّعِيفَ، وَالمَرِيضَ، فَإِذَا صَلَّى وَحْدَهُ فَلْيُصَلِّ كَيْفَ شَاءَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ئێك ژ هه‌وه‌ نڤێژ ل به‌را مرۆڤان كر بلا نڤێژێ سڤك بكه‌ت، چونكى د ناڤ وان دا یێ بچویك و مه‌زن و لاواز و نه‌خۆش هه‌یه‌، و چى گاڤا وى ب تنێ نڤێژ كر وى چاوا دڤێت بلا وه‌سا نڤێژێ بكه‌ت.', NULL, true),
  (1836, 'ڕەنگەكێ خۆمەزنكرنێ', 'عَنْ عَبْدِ اللهِ بْنِ عُمَرَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «مَنْ جَرَّ ثَوْبَهُ خُيَلاَءَ لَمْ يَنْظُرِ الله إِلَيْهِ يَوْمَ الْقِيَامَةِ» فَقَالَ أَبُو بَكْرٍ: إِنَّ أَحَدَ شِقَّيْ ثَوْبِي يَسْتَرْخِي إِلاَّ أَنْ أَتَعَاهَدَ ذَلِكَ مِنْهُ، فَقَالَ رَسُولُ اللهﷺ : «إِنَّكَ لَسْتَ تَصْنَعُ ذَلِكَ خُيَلاَءَ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ بۆ خۆمه‌زنكرن كراسێ خۆ ب دویڤ خۆ ڕا بكێشت خودێ ڕۆژا قیامه‌تێ به‌رێ خۆ ناده‌تێ. ئه‌بوو به‌كرى گۆت: ڕه‌خه‌كێ كراسێ من شۆڕ دبت ئه‌گه‌ر ئه‌ز وى هل نه‌ده‌م، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: تو وێ چه‌ندێ بۆ خۆمه‌زنكرنێ ناكه‌ى.', NULL, true),
  (1846, 'دورستییا یاریكرنێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: بَيْنَمَا الحَبَشَةُ يَلْعَبُونَ عِنْدَ رَسُولِ اللهﷺ بِحِرَابِهِمْ، إِذْ دَخَلَ عُمَرُ بْنُ الخَطَّابِ، فَأَهْوَى إِلَى الحَصْبَاءِ يَحْصِبُهُمْ بِهَا، فَقَالَ لَهُ رَسُولُ اللهﷺ : «دَعْهُمْ يَا عُمَرُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: ده‌مه‌كى حه‌به‌شییان ل نك پێغه‌مبه‌رى -سلاڤ لێ بن- یارى ب ڕمێن خۆ دكرن، عومه‌رێ كوڕێ خه‌ططابى هـاتـه‌ وێــڕێ، و وى ده‌ســـت دا هنده‌ك به‌ركان و د وان وه‌ركرن، ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- گۆتێ: وان بهێله‌ عومه‌ر.', NULL, true),
  (1856, 'خێرا قەنجییا د گەل حەیوانى', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «بَيْنَمَا رَجُلٌ يَمْشِي بِطَرِيقٍ اشْتَدَّ عَلَيْهِ الْعَطَشُ، فَوَجَدَ بِئْرًا، فَنَزَلَ فِيهَا فَشَرِبَ، ثُمَّ خَرَجَ فَإِذَا كَلْبٌ يَلْهَثُ يَأْكُلُ الثَّرَى مِنَ الْعَطَشِ، فَقَالَ الرَّجُلُ: لَقَدْ بَلَغَ هَذَا الْكَلْبَ مِنَ الْعَطَشِ مِثْلُ الَّذِي كَانَ بَلَغَ مِنِّي، فَنَزَلَ الْبِئْرَ فَمَلَأَ خُفَّهُ مَاءً، ثُمَّ أَمْسَكَهُ بِفِيهِ حَتَّى رَقِيَ فَسَقَى الْكَلْبَ فَشَكَرَ اللهُ لَهُ فَغَفَرَ لَهُ» قَالُوا: يَا رَسُولَ الله وَإِنَّ لَنَا فِي هَذِهِ الْبَهَائِمِ لَأَجْرًا؟ فَقَالَ: «فِي كُلِّ كَبِدٍ رَطْبَةٍ أَجْرٌ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: ده‌مه‌كى زه‌لامه‌ك ل ڕێكه‌كێ دچوو زێده‌ تێنى بوو، و وى بیره‌ك دیت، چوو خوارێ و ئاڤ ژێ ڤه‌خوار، پاشى ده‌ركه‌فت، هنگى وى صه‌یه‌ك دیت ئه‌زمان د ده‌ڤى دا هاتبوو، ژ تێنا دا بێن دكره‌ ئاخێ، زه‌لامى گۆت: ئه‌ڤه‌ ژى وه‌كى من یێ تێنى بووى، ئینا ئه‌و چوو د بیرێ دا و خوفكا خۆ تژى ئاڤ كر و كره‌ د ده‌ڤێ خۆ دا حه‌تا ب سه‌ر كه‌فتى، و صه‌ ئاڤداى، ئینا خودێ كارێ وى قه‌بویل كر و گونه‌هێن وى بۆ ژێبرن، گۆتن: ئه‌ى پێغه‌مبه‌ر، ما د حه‌یوانان ژى دا خێر بۆ مه‌ هه‌یه‌؟ وى گۆت: د هه‌ر خودان مێلاكه‌كا ته‌ڕ دا خێر هه‌یه‌.', NULL, true),
  (1866, 'گونەها ئازاردانا حەیوانى', 'عَنْ عَبْدِ الله بن عمر رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «عُذِّبَتِ امْرَأَةٌ فِي هِرَّةٍ سَجَنَتْهَا حَتَّى مَاتَتْ فَدَخَلَتْ فِيهَا النَّارَ، لَا هِيَ أَطْعَمَتْهَا وَسَقَتْهَا، إِذْ حَبَسَتْهَا، وَلَا هِيَ تَرَكَتْهَا تَأْكُلُ مِنْ خَشَاشِ الْأَرْضِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ژنه‌ك هاته‌ عه‌زابدان ژ به‌ر پشیكه‌كێ وێ ئه‌و گرتبوو حه‌تا مرى ڤێجا ئه‌و ژ به‌ر وێ چوو ئاگرى، ژ به‌ر كو وێ ئه‌و گرتبوو وێ نه‌ خوارن نه‌ ڤه‌خوارن نه‌دایێ، و نه‌هێلا ئه‌و بچت ژ كه‌سكاتییێ عه‌ردى بخۆت.', NULL, true),
  (1876, 'حەرامییا (حیلێن شەرعى!)', 'عَنْ جَابِرِ بْنِ عَبْدِ الله رضي الله عنه أَنَّهُ سَمِعَ رَسُولَ اللهﷺ يَقُولُ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ: «إِنَّ اللهَ وَرَسُولَهُ حَرَّمَ بَيْعَ الخَمْرِ، وَالمَيْتَةِ، وَالْخِنْزِيرِ، وَالْأَصْنَامِ»، فَقِيلَ: يَا رَسُولَ الله، أَرَأَيْتَ شُحُومَ المَيْتَةِ، فَإِنَّهُ يُطْلَى بِهَا السُّفُنُ، وَيُدْهَنُ بِهَا الجُلُودُ، وَيَسْتَصْبِحُ بِهَا النَّاسُ، فَقَالَ: «لَا، هُوَ حَرَامٌ»، ثُمَّ قَالَ رَسُولُ اللهﷺ عِنْدَ ذَلِكَ: «قَاتَلَ اللهُ الْيَهُودَ، إِنَّ اللهَ عَزَّ وَجَلَّ لَمَّا حَرَّمَ عَلَيْهِمْ شُحُومَهَا أَجْمَلُوهُ، ثُمَّ بَاعُوهُ فَأَكَلُوا ثَمَنَهُ».', 'جابرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: ل سالا ڤه‌كرنا مه‌كه‌هێ من ل مه‌كه‌هێ گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: هندى خودێ و پێغه‌مبه‌رێ وییه‌ فرۆتنا مه‌یێ و مرارى و به‌رازى و صه‌نه‌مان حه‌رامكرییه‌. گۆتن: ئه‌ى پێغه‌مبه‌رێ خودێ، تو چ دبێژى بۆ به‌زێ مراران، ئه‌وى د گه‌مییان دده‌ن، و چه‌رمى پێ دۆن دده‌ن، و خه‌لك وى بۆ چرایان ب كار دئینت؟ پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: نه‌ ئه‌و حه‌رامه‌، پاشى گۆت: خودێ جوهییان بكوژت! ده‌مێ خودێ به‌زێ مراران ل سه‌ر وان حه‌رامكرى وان ئه‌و حه‌لاند پاشى فرۆت و پارێ وى خوار.', NULL, true),
  (1886, 'حەرامییا مەیێ', 'عَنِ ابْنِ عُمَرَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «كُلُّ مُسْكِرٍ خَمْرٌ، وَكُلُّ مُسْكِرٍ حَرَامٌ، وَمَنْ شَرِبَ الخَمْرَ فِي الدُّنْيَا فَمَاتَ وَهُوَ يُدْمِنُهَا لَمْ يَتُبْ، لَمْ يَشْرَبْهَا فِي الْآخِرَةِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ر ڤه‌خوارنه‌كا عه‌قلى ببه‌ت مه‌یه‌، و هه‌ر ڤه‌خوارنه‌كا عه‌قلى ببه‌ت حه‌رامه‌، و هه‌چییێ مه‌یێ ل دنیایێ ڤه‌خۆت و بمرت و ئه‌و وێ ڤه‌دخۆت و تۆبه‌ نه‌كه‌ت، ئه‌و وێ ل ئاخره‌تێ ڤه‌ناخۆت.', NULL, true),
  (1896, 'بێنفرەهییا پێغەمبەرى', 'عن عَبْدِ الله بن مسعود رضي الله عنه قَالَ: قَسَمَ النَّبِيُّﷺ قَسْمًا، فَقَالَ رَجُلٌ: إِنَّ هَذِهِ لَقِسْمَةٌ مَا أُرِيدَ بِهَا وَجْهُ الله! فَأَتَيْتُ النَّبِيَّﷺ فَأَخْبَرْتُهُ، فَغَضِبَ حَتَّى رَأَيْتُ الْغَضَبَ فـِي وَجْهِهِ، ثُمَّ قَــالَ: «يَرْحَمُ اللَّهَ مُوسَى قَدْ أُوذِيَ بِأَكْثَرَ مِنْ هَذَا فَصَبَرَ».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پـێـغـه‌مـبـه‌رى -سلاڤ لێ بن- ماله‌ك لێكڤه‌كر، ئینا زه‌لامه‌كى گۆت: ئه‌ڤه‌ لێكڤه‌كرنه‌كه‌ مه‌خسه‌د پێ كنارێ خودێ نه‌بوویه‌! ئه‌ز هاتم من ئه‌و گۆتن بۆ پێغه‌مبه‌رى -سلاڤ لێ بن- ڤه‌گێڕا، كه‌ربێن وى ڤه‌بوون حه‌تا من ئه‌و د دێمێ وى دا دیتى، پاشى گۆت: خودێ ره‌حمێ ب مووسایى ببه‌ت، ئه‌و ژ ڤێ پتر هاته‌ ئێشاندن و وى صه‌بر كێشا.', NULL, true),
  (1906, NULL, 'عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: كُنْتُ أَمْشِي مَعَ رَسُولِ اللهﷺ، وَعَلَيْهِ رِدَاءٌ نَجْرَانِيٌّ غَلِيظُ الحَاشِيَةِ، فَأَدْرَكَهُ أَعْرَابِيٌّ، فَجَبَذَهُ بِرِدَائِهِ جَبْذَةً شَدِيدَةً، نَظَرْتُ إِلَى صَفْحَةِ عُنُقِ رَسُولِ اللهﷺ وَقَدْ أَثَّرَتْ بِهَا حَاشِيَةُ الرِّدَاءِ، مِنْ شِدَّةِ جَبْذَتِهِ، ثُمَّ قَالَ: يَا مُحَمَّدُ مُرْ لِي مِنْ مَالِ الله الَّذِي عِنْدَكَ، فَالْتَفَتَ إِلَيْهِ رَسُولُ اللهﷺ فَضَحِكَ، ثُمَّ أَمَرَ لَهُ بِعَطَاءٍ.', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: ئه‌ز د گه‌ل پێغه‌مبه‌رى -سلاڤ لێ بن- دچووم، و كراسه‌كێ نه‌جرانى یێ لێڤ خه‌رجیكرى د به‌ر بوو، ئه‌عرابییه‌ك ڤێڕا گه‌هشت و ب دژوارى كراسێ وى كێشا، حه‌تا من ستویێ پێغه‌مبه‌رى -سلاڤ لێ بن- دیت لێڤا كراسێ وى تێدا چوو خوار، پاشى وى ئه‌عرابى گـۆت: هــنــده‌كێ ژ مــالـێ خودێ یێ ل نك ته‌ هه‌ى بده‌ من، پێغه‌مبه‌ر -سلاڤ لێ بن- لێ زڤڕى و كه‌نى و فه‌رمان دا هنده‌ك مالى بده‌نێ.', NULL, true),
  (1916, 'عەزابا ڕەنگەكێ منافقان', 'عَـنْ أُسَـامَـةَ بْنِ زَيْدٍ رضي الله عنه قال: سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «يُؤْتَى بِالرَّجُلِ يَوْمَ الْقِيَامَةِ، فَيُلْقَى فِي النَّارِ، فَتَنْدَلِقُ أَقْتَابُ بَطْنِهِ، فَيَدُورُ بِهَا كَمَا يَدُورُ الْحِمَارُ بِالرَّحَى، فَيَجْتَمِعُ إِلَيْهِ أَهْلُ النَّارِ، فَيَقُولُونَ: يَا فُلَانُ مَا لَكَ؟ أَلَمْ تَكُنْ تَأْمُرُ بِالمَعْرُوفِ، وَتَنْهَى عَنِ المُنْكَرِ؟ فَيَقُولُ: بَلَى، قَدْ كُنْتُ آمُرُ بِالمَعْرُوفِ وَلَا آتِيهِ، وَأَنْهَى عَنِ المُنْكَرِ وَآتِيهِ».', 'ئوسامه‌یێ كوڕێ زه‌یدى -خودێ ژ هه‌ردویان رازى بت- دبێژت: مـــن گــوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: ڕۆژا قیامه‌تێ زه‌لامه‌كى دئینن دهاڤێنه‌ د ئاگرى دا، ڤێجا ڕویڤیكێن وى دكه‌ڤن و ئه‌و ل دۆر دزڤڕت كانێ چاوا كه‌ر ل دۆر جه‌نجه‌رێ دزڤڕت، ڤێجا جه‌هنه‌مى لێ كۆم دبن و دبێژن: فلان! ته‌ خێره‌؟ ما ته‌ فه‌رمان ب باشییێ نه‌دكر و ته‌ پاشڤه‌برن ژ خرابییێ نه‌دكر؟ ئه‌و دێ بێژت: به‌لێ من فه‌رمان ب باشییێ دكر و من ئه‌و نه‌دكر، و من پاشڤه‌برن ژ خرابییێ دكر و من ئه‌و دكر.', NULL, true),
  (1926, 'فرەهییا رەحما خودێ', 'عن أَبي هُرَيْرَةَ رضي الله عنه قَالَ: سَمِعْتُ النَّبِيَّﷺ قَالَ: «إِنَّ عَبْدًا أَصَابَ ذَنْبًا -وَرُبَّمَا قَالَ: أَذْنَبَ ذَنْبًا- فَقَالَ: رَبِّ أَذْنَبْتُ -وَرُبَّمَا قَالَ أَصَبْتُ- فَاغْفِرْ لِي، فَقَالَ رَبُّهُ: أَعَلِمَ عَبْدِي أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِهِ؟ غَفَرْتُ لِعَبْدِي، ثُمَّ مَكَثَ مَا شَاءَ الله، ثُمَّ أَصَابَ ذَنْبًا -أَوْ أَذْنَبَ ذَنْبًا- فَقَالَ: رَبِّ أَذْنَبْتُ -أَوْ أَصَبْتُ- آخَرَ فَاغْفِرْهُ، فَقَالَ: أَعَلِمَ عَبْدِي أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِهِ؟ غَفَرْتُ لِعَبْدِي، ثُمَّ مَكَثَ مَا شَاءَ الله، ثُمَّ أَذْنَبَ ذَنْبًا -وَرُبَّمَا قَالَ أَصَابَ ذَنْبًا- قَالَ: رَبِّ أَصَبْتُ -أَوْ قَالَ أَذْنَبْتُ- آخَرَ فَاغْفِرْهُ لِي، فَقَالَ: أَعَلِمَ عَبْدِي أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِهِ؟ غَفَرْتُ لِعَبْدِي –ثَلَاثًا- فَلْيَعْمَلْ مَا شَاءَ».', 'ئــه‌بــوو هـــوره‌یــره‌ -خودێ ژێ رازى بت- دبێژت: مـــن گــوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: عه‌بده‌كى گونه‌هه‌ك كر و گۆت: یا ره‌بى من گونه‌هه‌ك كر تو من بغه‌فرینه‌، ئینا خودایێ وى گۆت: ئه‌رێ عه‌بدێ من زانى كو وى خودایه‌ك هه‌یه‌ گونه‌هێ ژێ دبه‌ت و پێ دگرت؟ من عه‌بدێ خۆ غه‌فراند، پاشى هندى خودێ حه‌زكرى ئه‌و ما، پاشى وى گونه‌هه‌ك كر و گۆت: یا ره‌بى من گونه‌هه‌كا دى كر تو من بغه‌فرینه‌، ئینا خودایێ وى گۆت: ئه‌رێ عه‌بدێ من زانى كو وى خودایه‌ك هه‌یه‌ گونه‌هێ ژێ دبه‌ت و پێ دگرت؟ من عه‌بدێ خۆ غه‌فراند، پاشى هندى خودێ حه‌زكرى ئه‌و ما، پاشى وى گونه‌هه‌كا دى كر و گۆت: یا ره‌بى من گونه‌هه‌ك كر تو من بغه‌فرینه‌، ئینا خودایێ وى گۆت: ئه‌رێ عه‌بدێ من زانى كــو وى خــودایـه‌ك هه‌یه‌ گونه‌هێ ژێ دبه‌ت و پێ دگرت؟ من عه‌بدێ خۆ غه‌فراند -سێ جاران- ڤێجا وى چ دڤێت بلا بكه‌ت.', NULL, true);